#include <iostream>
#include <iomanip>

using namespace std;

int main()
{
    int L;
    char op;

    cin >> L;
    cin >> op;

    double a[12][12];

    for (int i = 0; i < 12; i++)
    {
        for (int j = 0; j < 12; j++)
        {
            cin >> a[i][j];
        }
    }

    double sum = 0;

    for (int j = 0; j < 12; j++)
    {
        sum += a[L][j];
    }

    if (op == 'M')
    {
        sum /= 12;
    }

    cout << fixed << setprecision(1) << sum << endl;

    return 0;
}
